from collections import defaultdict

class BigramLM:
    def __init__(self):
        self.bigram_counts = defaultdict(lambda: defaultdict(int))
        self.unigram_counts = defaultdict(int)
        self.vocab = set()

    def train(self, corpus: list[list[str]]) -> None:
        for sentence in corpus:
            for i in range(len(sentence)):
                self.unigram_counts[sentence[i]] += 1
                self.vocab.add(sentence[i])
                if i > 0:
                    self.bigram_counts[sentence[i-1]][sentence[i]] += 1

    def prob(self, word: str, context: str) -> float:
        V = len(self.vocab)
        num = self.bigram_counts[context][word] + 1
        denom = self.unigram_counts[context] + V
        return num / denom
